example.code:
{
  "protocol_version": "1.0.0",
  "lanes": [
    "hallucination",
    "refusal",
    "wrong-tool",
    "out-of-scope",
    "cost-spike"
  ],
  "steps": [
    {
      "id": "s1",
      "input": "ticket.payload",
      "owner": "ml-eng-oncall",
      "exit_criterion": "lane assigned",
      "output_location": "triage/{id}.json"
    },
    {
      "id": "s2",
      "input": "triage/{id}.json",
      "owner": "ml-eng-oncall",
      "exit_criterion": "owner notified",
      "output_location": "PagerDuty"
    },
    {
      "id": "s3",
      "input": "PagerDuty ack",
      "owner": "lane-owner",
      "exit_criterion": "mitigation decision",
      "output_location": "incident/{id}.md"
    },
    {
      "id": "s4",
      "input": "incident/{id}.md",
      "owner": "ml-eng",
      "exit_criterion": "golden candidate created",
      "output_location": "golden/candidates/"
    }
  ],
  "decision_branches": [
    {
      "signal": "ticket.labels CONTAINS hallucination OR feedback.score < 0.5",
      "lane_when_true": "hallucination",
      "lane_when_false": "out-of-scope"
    }
  ],
  "owner": "jane@team.io",
  "deviation_log_uri": "https://team.io/playbooks/triage/deviations.log"
}
